args.sparql:
SELECT ?team (COUNT(?ownEvent) AS ?premierships)
WHERE {
  ?event wdt:P1651 wd:Q388556 ;
         wdt:P190 wd:Q381514 ;
         wdt:P1543 ?team .
  FILTER (?team != wd:Q381514)
  ?team wdt:P131 wd:Q25222 .
  ?ownEvent wdt:P190 ?team ;
             wdt:P1651 wd:Q388556 .
}
GROUP BY ?team
ORDER BY DESC(?premierships)
LIMIT 1
OFFSET 1
